"""
Unified interface ke berbagai LLM API. Semua return format sama:
{
  "content": "<text dari model, bisa kosong>",
  "tool_calls": [{"id": "...", "name": "...", "arguments": {...}}]
}
"""
import json
import time
import requests
import config


class BaseProvider:
    name = "base"

    def chat(self, messages, tools, on_token=None):
        raise NotImplementedError


CONTEXT_WINDOWS = {
    "llama-3.3-70b-versatile": 128_000,
    "claude-sonnet-4-6": 200_000,
    "gpt-4o-mini": 128_000,
    "mimo-v2.5": 128_000,
    "mimo": 128_000,
}

RETRYABLE_STATUS = {429, 500, 502, 503, 529}
MAX_RETRIES = 4
BASE_BACKOFF = 2


def _request_with_retry(method, url, **kwargs):
    last_exc = None
    for attempt in range(MAX_RETRIES + 1):
        try:
            resp = method(url, **kwargs)
        except requests.exceptions.RequestException as e:
            last_exc = e
            if attempt == MAX_RETRIES:
                raise
            time.sleep(BASE_BACKOFF * (2 ** attempt))
            continue

        if resp.status_code in RETRYABLE_STATUS and attempt < MAX_RETRIES:
            wait = BASE_BACKOFF * (2 ** attempt)
            retry_after = resp.headers.get("retry-after")
            if retry_after:
                try:
                    wait = max(wait, float(retry_after))
                except ValueError:
                    pass
            time.sleep(wait)
            continue

        return resp

    if last_exc:
        raise last_exc
    return resp


class OpenAICompatProvider(BaseProvider):
    def __init__(self, api_key, base_url, model):
        self.api_key = api_key
        self.base_url = base_url.rstrip("/")
        self.model = model
        self.context_window = CONTEXT_WINDOWS.get(model, 128_000)

    def chat(self, messages, tools, on_token=None, max_tokens=None):
        stream = on_token is not None
        payload = {
            "model": self.model,
            "messages": messages,
            "max_tokens": max_tokens or config.MAX_TOKENS,
            "stream": stream,
        }
        if tools:
            payload["tools"] = tools
            payload["tool_choice"] = "auto"
        if stream:
            payload["stream_options"] = {"include_usage": True}

        resp = _request_with_retry(
            requests.post,
            f"{self.base_url}/chat/completions",
            headers={
                "Authorization": f"Bearer {self.api_key}",
                "Content-Type": "application/json",
            },
            json=payload,
            timeout=60,
            stream=stream,
        )
        resp.raise_for_status()

        if not stream:
            data = resp.json()
            msg = data["choices"][0]["message"]
            tool_calls = []
            for tc in msg.get("tool_calls") or []:
                raw_args = tc["function"]["arguments"] or "{}"
                try:
                    parsed_args = json.loads(raw_args)
                except Exception:
                    parsed_args = {}
                tool_calls.append(
                    {
                        "id": tc["id"],
                        "name": tc["function"]["name"],
                        "arguments": parsed_args,
                    }
                )
            u = data.get("usage", {}) or {}
            usage = {
                "input": u.get("prompt_tokens", 0),
                "output": u.get("completion_tokens", 0),
                "total": u.get("total_tokens", 0),
            }
            return {
                "content": msg.get("content") or "",
                "tool_calls": tool_calls,
                "raw_message": msg,
                "usage": usage,
            }

        content = ""
        tool_calls_acc = {}
        usage = {"input": 0, "output": 0, "total": 0}

        for line in resp.iter_lines():
            if not line:
                continue
            line = line.decode("utf-8")
            if not line.startswith("data: "):
                continue
            payload_str = line[len("data: "):]
            if payload_str.strip() == "[DONE]":
                break
            try:
                chunk = json.loads(payload_str)
            except Exception:
                continue

            choice = (chunk.get("choices") or [{}])[0]
            delta = choice.get("delta", {})

            if delta.get("content"):
                piece = delta["content"]
                content += piece
                on_token(piece)

            for tc in delta.get("tool_calls") or []:
                idx = tc.get("index", 0)
                acc = tool_calls_acc.setdefault(idx, {"id": None, "name": "", "arguments": ""})
                if tc.get("id"):
                    acc["id"] = tc["id"]
                fn = tc.get("function") or {}
                if fn.get("name"):
                    acc["name"] += fn["name"]
                if fn.get("arguments"):
                    acc["arguments"] += fn["arguments"]

            u = chunk.get("usage")
            if u:
                usage = {
                    "input": u.get("prompt_tokens", 0),
                    "output": u.get("completion_tokens", 0),
                    "total": u.get("total_tokens", 0),
                }

        tool_calls = []
        for idx in sorted(tool_calls_acc):
            acc = tool_calls_acc[idx]
            try:
                args = json.loads(acc["arguments"] or "{}")
            except Exception:
                args = {}
            tool_calls.append({"id": acc["id"] or f"call_{idx}", "name": acc["name"], "arguments": args})

        return {"content": content, "tool_calls": tool_calls, "raw_message": None, "usage": usage}


