                "system": system,
                "messages": conv,
                "tools": self._convert_tools(tools),
                "stream": stream,
            },
            timeout=60,
            stream=stream,
        )
        resp.raise_for_status()

        if not stream:
            data = resp.json()
            content_text = ""
            tool_calls = []
            for block in data.get("content", []):
