def get_provider(name: str = None):
    name = (name or config.DEFAULT_PROVIDER).lower()
    if name in ("auto", "fallback", ""):
        try:
            return FallbackProvider()
        except Exception:
            pass
    if name == "cerebras":
        return OpenAICompatProvider(
            config.CEREBRAS_API_KEY, config.CEREBRAS_BASE_URL, config.CEREBRAS_MODEL,
        )
    if name == "mistral":
        return OpenAICompatProvider(
            config.MISTRAL_API_KEY, config.MISTRAL_BASE_URL, config.MISTRAL_MODEL,
        )
    if name == "mimo_backup":
        return OpenAICompatProvider(
            config.MIMO_BACKUP_KEY, config.MIMO_BASE_URL, config.MIMO_MODEL,
        )
    if name == "nvidia":
        return OpenAICompatProvider(
            config.NVIDIA_API_KEY, config.NVIDIA_BASE_URL, config.NVIDIA_MODEL,
        )
    return _get_provider_orig(name)

